import{_ as e,o as l,c as a,ae as t}from"./chunks/framework.B-4rAn0z.js";const p=JSON.parse('{"title":"为什么选择它","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/why.md","filePath":"zh/guide/why.md"}'),o={name:"zh/guide/why.md"};function n(s,i,c,r,d,g){return l(),a("div",null,[...i[0]||(i[0]=[t('<h1 id="为什么选择它" tabindex="-1">为什么选择它 <a class="header-anchor" href="#为什么选择它" aria-label="Permalink to &quot;为什么选择它&quot;">​</a></h1><h2 id="现实问题" tabindex="-1">现实问题 <a class="header-anchor" href="#现实问题" aria-label="Permalink to &quot;现实问题&quot;">​</a></h2><p>在真实业务里，图标通常会变成一类“高频但琐碎”的问题：</p><ul><li>图标文件分散、命名不统一，依赖手动导入和维护路径。</li><li>经常退回到 <code>&lt;img src&gt;</code> 或零散 inline SVG，复用成本高。</li><li>颜色、尺寸和响应式控制不统一，样式治理困难。</li><li>开发、构建、SSR 各阶段行为可能不一致，排查成本高。</li></ul><p>问题并不在 SVG 本身，而在于图标流程没有成为构建体系的一部分。</p><h2 id="为什么会有-vite-plugin-svg-icons-ng" tabindex="-1">为什么会有 <code>vite-plugin-svg-icons-ng</code> <a class="header-anchor" href="#为什么会有-vite-plugin-svg-icons-ng" aria-label="Permalink to &quot;为什么会有 `vite-plugin-svg-icons-ng`&quot;">​</a></h2><p><code>vite-plugin-svg-icons-ng</code> 的目标是把图标能力标准化：</p><ul><li>以本地 SVG 文件作为唯一来源。</li><li>自动生成 SVG 精灵，不再手动维护产物。</li><li>用统一方式注入与消费图标。</li><li>借助缓存与 HMR 提升开发反馈速度。</li></ul><p>核心诉求很直接：让图标从“需要管理的资源”，变成“可以直接使用的能力”。</p><h2 id="与-vite-plugin-svg-icons-的关系" tabindex="-1">与 <code>vite-plugin-svg-icons</code> 的关系 <a class="header-anchor" href="#与-vite-plugin-svg-icons-的关系" aria-label="Permalink to &quot;与 `vite-plugin-svg-icons` 的关系&quot;">​</a></h2><ul><li>本项目受到 <a href="https://github.com/vbenjs/vite-plugin-svg-icons" target="_blank" rel="noreferrer"><code>vite-plugin-svg-icons</code></a> 的启发，并延续其基于 sprite 的核心思路。</li><li><code>vite-plugin-svg-icons-ng</code> 在此基础上做了全新功能实现、代码组织与文档管理，面向本仓库持续演进。</li><li>为降低迁移成本，保留了旧 虚拟模块 id 的过渡路径，同时推荐使用新 虚拟模块 id： <ul><li><code>virtual:svg-icons/register</code></li><li><code>virtual:svg-icons/ids</code></li></ul></li></ul>',11)])])}const h=e(o,[["render",n]]);export{p as __pageData,h as default};
